def edit_file(self, filename: str) -> None:
    import subprocess

    editor = self.get_editor()
    environ: dict[str, str] | None = None

    if self.env:
        environ = os.environ.copy()
        environ.update(self.env)

    popen_kwargs: dict[str, t.Any] = {}

    if WIN and self.process_priority is not None:
        class_name = _WIN_PRIORITY_CLASS_NAMES[self.process_priority]
        priority_class = getattr(subprocess, class_name, None)

        if priority_class is not None:
            popen_kwargs["creationflags"] = priority_class

    try:
        c = subprocess.Popen(
            f'{editor} "{filename}"', env=environ, shell=True, **popen_kwargs
        )

        if not WIN and self.process_priority is not None:
            nice_value = _UNIX_PRIORITY_NICE_VALUES[self.process_priority]

            try:
                os.setpriority(os.PRIO_PROCESS, c.pid, nice_value)
            except (AttributeError, OSError, PermissionError):
                # ``os.setpriority`` may be unavailable, or the process
                # may lack permission to raise its priority. Editing
                # should still proceed with the default priority.
                pass

        exit_code = c.wait()

